# Load the encryption key from the application config
def load_key():
    return os.environ.get("ENCRYPTION_KEY").encode()

# Generate a new key and save it to the environment variable for demonstration purposes
def generate_key():
    key = Fernet.generate_key()
    os.environ["ENCRYPTION_KEY"] = key.decode()
    return key

# Encrypt the credit card number
def encrypt_credit_card(card_number):
    key = load_key()
    fernet = Fernet(key)
    encrypted_card = fernet.encrypt(card_number.encode())
    return encrypted_card

# Decrypt the credit card number
def decrypt_credit_card(encrypted_card):
    key = load_key()
    fernet = Fernet(key)
    decrypted_card = fernet.decrypt(encrypted_card).decode()
    return decrypted_card

